<style lang="scss">
.sale-after-form {
  .el-form-item {
    &:nth-child(1) {
      .el-form-item__label {
        display: none;
      }
    }
  }
  .receive-info {
    margin-top: 10px;
    background: #f5f5f5;
    padding: 10px;
  }
  .el-select {
    width: 260px;
  }
  .el-textarea {
    width: 500px;
  }
}
</style>
<template>
  <div>
    <!-- form: {{ form }} -->
    <SpForm
      ref="form"
      v-model="form"
      class="sale-after-form"
      :form-list="formList"
      :submit="false"
      @onSubmit="onSubmit"
    />

    <div class="footer-container">
      <el-button
        @click="
          () => {
            this.$router.go(-1)
          }
        "
      >
        取消
      </el-button>
      <el-button
        type="primary"
        @click="
          () => {
            this.$refs['form'].handleSubmit()
          }
        "
      >
        儲存
      </el-button>
    </div>
  </div>
</template>

<script>
import CompReceiveInfo from '../normalorders/components/comp-receiveInfo'
import CompGoodsList from './comps/comp-goodsList'
import CompRefundAmount from './comps/comp-refundAmount'
import CompRefundPoint from './comps/comp-refundPoint'

const REASONS = [
  { title: '收到殘次品', value: '1' },
  { title: '商品有汙漬', value: '2' },
  { title: '包裝破損導致商品損壞', value: '3' },
  { title: '七天無理由退貨', value: '4' }
]
export default {
  name: '',
  data() {
    return {
      orderInfo: null,
      form: {
        order_id: '',
        aftersales_type: 'ONLY_REFUND',
        reason: '1',
        goods_returned: false,
        items: [],
        refund_point: '0',
        refund_fee: '',
        description: '',
        pic: ''
      },
      formList: [
        {
          label: '',
          component: () => {
            const { id: order_id } = this.$route.params
            return <CompReceiveInfo orderId={order_id} on-onLoad={this.onLoad} />
          }
        },
        {
          label: '售後形式',
          key: 'aftersales_type',
          type: 'radio',
          options: [
            { label: 'ONLY_REFUND', name: '僅退款（無需退貨）' },
            { label: 'REFUND_GOODS', name: '退貨退款' }
          ],
          onChange: (e) => {
            if (e == 'REFUND_GOODS') {
              this.formList[6].isShow = true
            } else {
              this.formList[6].isShow = false
            }
          }
        },
        {
          label: '退款原因',
          key: 'reason',
          placeholder: '請選擇退款原因',
          type: 'select',
          options: REASONS
        },
        {
          label: '退款商品',
          key: 'items',
          component: () => (
            <CompGoodsList
              ref='compGoodsRef'
              value={this.orderInfo}
              on-onChange={(e) => {
                this.form.items = e
                this.$refs['compRefundRef'].getTotalFee()
              }}
            />
          ),
          validator: (rule, value, callback) => {
            if (this.form.items.length > 0) {
              callback()
            } else {
              callback('請選擇售後商品')
            }
          }
        },
        {
          label: '退積分',
          key: 'refund_point',
          component: () => (
            <CompRefundPoint
              value={this.orderInfo}
              on-onChange={(e) => {
                this.form.refund_point = e
              }}
            />
          ),
          validator: (rule, value, callback) => {
            if (this.form.refund_point >= 0) {
              callback()
            } else {
              callback('積分不能為空')
            }
          }
        },
        {
          label: '退款金額',
          key: 'refund_fee',
          component: () => (
            <CompRefundAmount
              ref='compRefundRef'
              value={this.orderInfo}
              on-onChangeFee={(e) => {
                this.form.refund_fee = e
              }}
              on-onChange={(e) => {
                this.$refs['compGoodsRef'].setSelectAllGoods()
                {
                  /* this.form.refund_fee = e */
                }
              }}
            />
          ),
          validator: (rule, value, callback) => {
            if (!this.form.refund_fee) {
              callback('退款金額不能為空')
            } else if (this.form.refund_fee > this.$refs['compRefundRef'].refundFee) {
              callback('退款金額超過可退金額')
            } else {
              callback()
            }
          }
        },
        {
          label: '回寄方式',
          key: 'goods_returned',
          type: 'radio',
          options: [
            { label: false, name: '快遞出貨' },
            { label: true, name: '到店退貨（店員已驗貨）' }
          ],
          isShow: false
        },
        {
          label: '補充描述',
          key: 'description',
          type: 'textarea'
        },
        {
          label: '上傳憑證',
          key: 'pic',
          component: ({ key }, value) => {
            return <SpImagePicker v-model={value[key]} />
          }
          // component: () => <SpImagePicker v-model={this.form.pic} />
          // validator: (rule, value, callback) => {
          //   if (this.form.pic) {
          //     callback()
          //   } else {
          //     callback('請上傳憑證')
          //   }
          // }
        }
      ]
    }
  },
  created() {},
  methods: {
    onLoad({ orderInfo }) {
      orderInfo.items = orderInfo.items.map((item) => {
        return {
          ...item,
          refundNum: item.left_aftersales_num,
          checked: false
        }
      })

      this.orderInfo = orderInfo
    },
    async onSubmit() {
      await this.$confirm('請確認申請售後', '提示', {
        confirmButtonText: '確定',
        cancelButtonText: '取消'
      })
      const { id: order_id } = this.$route.params
      const reason = REASONS.find((item) => item.value == this.form.reason).title
      const params = {
        order_id,
        aftersales_type: this.form.aftersales_type,
        goods_returned: this.form.goods_returned,
        reason,
        detail: JSON.stringify(this.form.items),
        refund_fee: this.form.refund_fee * 100,
        refund_point: this.form.refund_point,
        description: this.form.description,
        evidence_pic: [this.form.pic]
      }
      await this.$api.trade.salesAfterApply(params)
      this.$message.success('售後申請提交成功')
      this.$EventBus.$emit('event.tradelist.refresh')
      setTimeout(() => {
        this.$router.go(-1)
      }, 1000)
      // const h = this.$createElement
      // let msgTxt = ''
      // if (params.aftersales_type == 'ONLY_REFUND') {
      //   msgTxt = '請耐心等待系統退款'
      // } else if (params.aftersales_type == 'REFUND_GOODS' && !params.goods_returned) {
      //   msgTxt = '請通知買家盡快寄回商品'
      // } else if (params.aftersales_type == 'REFUND_GOODS' && params.goods_returned) {
      //   msgTxt = '請耐心等待系統退款'
      // }
      // this.$msgbox({
      //   title: '申請售後',
      //   message: h('p', null, [
      //     h('i', {
      //       class: 'iconfont icon-check-circle',
      //       style: 'color: var(--themeColor); margin-right: 4px;'
      //     }),
      //     h('span', { style: 'color: #333' }, '售後申請提交成功'),
      //     h('div', { style: 'color: #999; font-size: 13px; margin-left: 20px;' }, msgTxt)
      //   ]),
      //   showCancelButton: true,
      //   confirmButtonText: '確定',
      //   cancelButtonText: '取消'
      // }).then((action) => {
      //   this.$EventBus.$emit('event.tradelist.refresh')
      //   setTimeout(() => {
      //     this.$router.go(-1)
      //   }, 1000)
      // })
    }
  }
}
</script>
